<?php
require_once dirname(__DIR__) . '/includes/functions.php';
employeePortalGuard();$user=currentUser();$pdo=getDB();$employee=employeeForCurrentUser($pdo,$user);if(!$employee){siteHeader('My Goals','login');echo '<div class="alert alert-warning">No employee profile is linked to your email.</div>';siteFooter();exit;}
$goals=$pdo->prepare('SELECT * FROM '.table('employee_goals').' WHERE employee_id=? ORDER BY due_date ASC');$goals->execute([(int)$employee['id']]);$goals=$goals->fetchAll();
$reviews=$pdo->prepare('SELECT * FROM '.table('employee_performance_reviews').' WHERE employee_id=? ORDER BY created_at DESC');$reviews->execute([(int)$employee['id']]);$reviews=$reviews->fetchAll();
siteHeader('My Goals','login');
?>
<h1 class="mb-4">My Goals & Reviews</h1><div class="row g-4"><div class="col-lg-7"><div class="table-card table-responsive"><h2 class="h5">Goals</h2><table class="table"><thead><tr><th>Goal</th><th>Target</th><th>Actual</th><th>Due</th><th>Status</th></tr></thead><tbody><?php foreach($goals as $g): ?><tr><td><strong><?php echo esc($g['goal_title']); ?></strong><div class="small text-secondary"><?php echo esc($g['target_metric']); ?></div></td><td><?php echo number_format((float)$g['target_value'],2); ?></td><td><?php echo number_format((float)$g['actual_value'],2); ?></td><td><?php echo esc($g['due_date']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($g['status'])); ?>"><?php echo esc($g['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div><div class="col-lg-5"><div class="table-card table-responsive"><h2 class="h5">Reviews</h2><table class="table"><thead><tr><th>Period</th><th>Rating</th><th>Status</th></tr></thead><tbody><?php foreach($reviews as $r): ?><tr><td><?php echo esc($r['review_period']); ?></td><td><?php echo number_format((float)$r['rating'],2); ?></td><td><span class="badge bg-<?php echo esc(statusTone($r['status'])); ?>"><?php echo esc($r['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php siteFooter(); ?>